class Solution:
    def maxSubstrings(self, word):
        n = len(word)
        dp = [0] * (n + 1)
        for i in range(n - 1, -1, -1):
            dp[i] = dp[i + 1]
            for j in range(i + 3, n):
                if word[j] == word[i]:
                    cand = 1 + dp[j + 1]
                    if cand > dp[i]:
                        dp[i] = cand
        return dp[0]

