class Solution:
    def maxSubstrings(self, word):
        first = {}
        count = 0
        start = 0
        for i, ch in enumerate(word):
            if ch in first and i - first[ch] + 1 >= 4:
                count += 1
                first = {}
                start = i + 1
            elif ch not in first:
                first[ch] = i
        return count

