var maxSubstrings = function(word) {
    let first = new Map();
    let count = 0;
    for (let i = 0; i < word.length; i++) {
        const ch = word[i];
        if (first.has(ch) && i - first.get(ch) + 1 >= 4) {
            count++;
            first = new Map();
        } else if (!first.has(ch)) {
            first.set(ch, i);
        }
    }
    return count;
};
